from diskcache import FanoutCache

logger = logging.getLogger(__name__)

# Magic header prefixed to compressed disk cache entries so that legacy (header-less) blobs
# written before this feature existed continue to be read back as raw pickled objects.
_CACHE_MAGIC = b"DSPC"
_CODEC_NONE = 0x00
_CODEC_GZIP = 0x01
_CODEC_ZLIB = 0x02
_CODEC_BY_NAME = {"gzip": _CODEC_GZIP, "zlib": _CODEC_ZLIB}


class Cache:
    """DSPy Cache

    `Cache` provides 2 levels of caching (in the given order):
        1. In-memory cache - implemented with cachetools.LRUCache
        2. On-disk cache - implemented with diskcache.FanoutCache
